CREATE TABLE "config"."validity_status" ("id" bigint NOT NULL GENERATED ALWAYS AS IDENTITY, "source" text NOT NULL DEFAULT '', "code" text NOT NULL, "status_class" text NOT NULL, "is_current_law" boolean NOT NULL DEFAULT false, "origin" text NOT NULL DEFAULT 'seed', "created_at" timestamptz NOT NULL DEFAULT now(), "updated_at" timestamptz NOT NULL DEFAULT now(), PRIMARY KEY ("id"), CONSTRAINT "uq_config_validity_status" UNIQUE ("source", "code"), CONSTRAINT "chk_config_validity_status_class" CHECK (status_class = ANY (ARRAY['in_force'::text, 'expired'::text, 'partial'::text, 'not_yet'::text, 'suspended'::text, 'inappropriate'::text])), CONSTRAINT "chk_config_validity_status_origin" CHECK (origin = ANY (ARRAY['seed'::text, 'user'::text])));
